const a = [
  {"id":1702,"text":"Which of the following parts of the ear connects the middle ear with the nasopharynx?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 974.","responses":[{"text":"Auditory ossicles","correct":false,"visible":false},{"text":"Tympanic cavity","correct":false,"visible":false},{"text":"Tympanic membrane","correct":false,"visible":false},{"text":"External acoustic meatus","correct":false,"visible":false},{"text":"Pharyngotympanic tube","correct":true,"visible":false}]},{"id":1703,"text":"Which of the following muscles acts synergetically with the masseter to elevate the mandible and produce smaller grinding movements?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 931.","responses":[{"text":"Mylohyoid","correct":false,"visible":false},{"text":"Geniohyoid","correct":false,"visible":false},{"text":"Lateral pterygoid","correct":false,"visible":false},{"text":"Medial pterygoid","correct":true,"visible":false},{"text":"Temporalis","correct":false,"visible":false}]},{"id":1704,"text":"Which bone of the basicranium is formed by endochondral ossification?","explanation":null,"reference":"Sphenoid bone - an overview | sciencedirect topics. Accessed April 16, 2022. https://www.sciencedirect.com/topics/neuroscience/sphenoid-bone","responses":[{"text":"Frontal","correct":false,"visible":false},{"text":"Vomer","correct":false,"visible":false},{"text":"Parietal","correct":false,"visible":false},{"text":"Sphenoidal","correct":true,"visible":false},{"text":"Lacrimal","correct":false,"visible":false}]},{"id":1705,"text":"Which of the following foramina is present as a large opening between the occipital bone and the petrous part of the temporal bone?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 830.","responses":[{"text":"Stylomastoid foramen","correct":false,"visible":false},{"text":"Foramen spinosum","correct":false,"visible":false},{"text":"Foramen ovale","correct":false,"visible":false},{"text":"Foramen lacerum","correct":false,"visible":false},{"text":"Jugular foramen","correct":true,"visible":false}]},{"id":1706,"text":"Complete the following: At the lower border of the posterior belly of the digastric muscle, the hypoglossal nerve turns forward and medially...","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1004.","responses":[{"text":"Loops around the occipital artery","correct":false,"visible":false},{"text":"Deep to the submandibular gland","correct":false,"visible":false},{"text":"Loops around the lingual artery","correct":false,"visible":false},{"text":"Deep to the lingual nerve","correct":false,"visible":false},{"text":"Loops around the occipital artery and crosses the external and internal carotid","correct":true,"visible":false}]},{"id":1707,"text":"Which of the following is the correct statement regarding the histology of the tongue?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 299-300.","responses":[{"text":"Taste buds are only found in filiform papillae","correct":false,"visible":false},{"text":"Filiform papillae are most numerous and keratinized","correct":true,"visible":false},{"text":"Dorsal surface of tongue is smooth and shows prominent lingual veins","correct":false,"visible":false},{"text":"Circumvalate papillae are present behind the sulcus terminalis","correct":false,"visible":false},{"text":"Lingual papillae are formed of stratified squamous epithelium only","correct":false,"visible":false}]},{"id":1708,"text":"Regarding the gross features of the larynx, which of the following is true?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1043-1045.","responses":[{"text":"Corniculate is a small rod shaped cartilage present on the upper lateral part of the cricoid cartilage","correct":false,"visible":false},{"text":"Arytenoid cartilage is small pyramidal in shape, lying on the inferior cornu of thyroid","correct":false,"visible":false},{"text":"Epiglottis is a a leaf shaped cartilage places in the posterior wall of the larynx","correct":false,"visible":false},{"text":"Upper part of the anterior border of the thyroid cartilage is separated by the thyroid notch","correct":true,"visible":false},{"text":"Thyroid cartilage is shaped like a ring and is elastic in nature","correct":false,"visible":false}]},{"id":1709,"text":"Which of the following is correct regarding the gross features of the skull and norma frontalis?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 824-825, 828.","responses":[{"text":"The bridge of the nose is formed by the frontal and zygomatic bones","correct":false,"visible":false},{"text":"The nasion is a median point of the root of the nose","correct":true,"visible":false},{"text":"Frontal eminence is a low, rounded elevation between two superciliary arches","correct":false,"visible":false},{"text":"Supraorbital margin of the orbital cavity is formed by the zygomatic bone","correct":false,"visible":false},{"text":"Glabella is a median elevation in the nasal bone","correct":false,"visible":false}]},{"id":1710,"text":"Which of the following is correct regarding gross anatomical features of the scalp?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 851-852. \r\n\r\n(2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 915.","responses":[{"text":"Behind the auricle of the scalp, it is supplied by the branches of the superficial temporal arteries","correct":false,"visible":false},{"text":"Loose areolar tissue extends anteriorly to the supraorbital margins of the frontal bone","correct":true,"visible":false},{"text":"Epicranial aponeurosis is tightly applied to the pericranium","correct":false,"visible":false},{"text":"Skin of the scalp is devoid of sebaceous glands","correct":false,"visible":false},{"text":"In front of the auricle, the scalp is supplied by the branches of the ophthalmic artery","correct":false,"visible":false}]},{"id":1711,"text":"Regarding the gross features of the norma occipitalis and normal lateralis, which of the following is the correct statement?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 449, 81, 837-838, 924.","responses":[{"text":"Lambdoid suture lies between the frontal and parietal bones","correct":false,"visible":false},{"text":"External occipital protuberance is a median protuberance in the norma occipitalis that marks the junction of the head and neck","correct":true,"visible":false},{"text":"Floor of the infratemporal fossa is pierced by the foramen ovale","correct":false,"visible":false},{"text":"Temporal lines are continuous from the norma lateralis to norma occipitalis","correct":false,"visible":false},{"text":"Roof of the infratemporal fossa is formed by the lesser wing of the sphenoid","correct":false,"visible":false}]},{"id":1712,"text":"The orbicularis oris, the muscle of facial expression, is inserted on which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 854.","responses":[{"text":"Mucous membranes of the lips","correct":true,"visible":false},{"text":"Skin of lower lip","correct":false,"visible":false},{"text":"Skin of upper lip","correct":false,"visible":false},{"text":"Major alar cartilage","correct":false,"visible":false},{"text":"Skin around the orbital margin","correct":false,"visible":false}]},{"id":1713,"text":"The mental artery supplying the muscles of the face is best described as a branch of which artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 864.","responses":[{"text":"Smaller terminal branch of the external carotid artery","correct":false,"visible":false},{"text":"External carotid artery","correct":false,"visible":false},{"text":"Internal carotid artery","correct":false,"visible":false},{"text":"Terminal branch of the facial artery","correct":false,"visible":false},{"text":"Terminal branch of inferior alveolar artery","correct":true,"visible":false}]},{"id":1715,"text":"The superior oblique muscle, attached to the body of the sphenoid, is innervated by which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 908.","responses":[{"text":"Facial nerve","correct":false,"visible":false},{"text":"Trochlear nerve","correct":true,"visible":false},{"text":"Optic nerve","correct":false,"visible":false},{"text":"Trigeminal nerve","correct":false,"visible":false},{"text":"Oculomotor nerve","correct":false,"visible":false}]},{"id":1716,"text":"The intermaxillary segment gives rise to which of the following structures in the development of the face?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 178.","responses":[{"text":"Soft palate","correct":false,"visible":false},{"text":"Primary palate","correct":true,"visible":false},{"text":"Upper molar arches","correct":false,"visible":false},{"text":"Secondary palate","correct":false,"visible":false},{"text":"Lower incisor teeth","correct":false,"visible":false}]},{"id":1717,"text":"The olfactory epithelium is derived from which embryonic structure?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 181.","responses":[{"text":"Neuroectoderm","correct":false,"visible":false},{"text":"Surface ectoderm","correct":true,"visible":false},{"text":"Endoderm","correct":false,"visible":false},{"text":"Neural crest cells","correct":false,"visible":false},{"text":"Mesoderm","correct":false,"visible":false}]},{"id":1718,"text":"The secretory part of the parotid gland is derived from which of the following germ layers?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 174.","responses":[{"text":"Endoderm","correct":false,"visible":false},{"text":"Neural crest cell","correct":false,"visible":false},{"text":"Neuroectoderm","correct":false,"visible":false},{"text":"Mesoderm","correct":false,"visible":false},{"text":"Ectoderm","correct":true,"visible":false}]},{"id":1719,"text":"The external acoustic meatus develops from which of the following parts of the pharyngeal apparatus?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 177.","responses":[{"text":"Tubotympanic recess","correct":false,"visible":false},{"text":"1st pharyngeal arch","correct":false,"visible":false},{"text":"2nd pharyngeal arch","correct":false,"visible":false},{"text":"1st pharyngeal groove","correct":true,"visible":false},{"text":"1st pharyngeal membrane","correct":false,"visible":false}]},{"id":1939,"text":"Hemorrhage in tonsil surgery is due to which of the following vessels?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1047, 1057.","responses":[{"text":"Maxillary vein","correct":false,"visible":false},{"text":"Paratonsillar vein","correct":true,"visible":false},{"text":"Lingual artery","correct":false,"visible":false},{"text":"Maxillary artery","correct":false,"visible":false},{"text":"Brachial artery","correct":false,"visible":false}]},{"id":1940,"text":"Which of the following leads to the development of the cerebellum?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 392.","responses":[{"text":"Metencephalon","correct":true,"visible":false},{"text":"Rhombencephalon","correct":false,"visible":false},{"text":"Medulla","correct":false,"visible":false},{"text":"Prosencephalon","correct":false,"visible":false},{"text":"Telencephalon","correct":false,"visible":false}]},{"id":1941,"text":"Tuning of sound is a function of turbinates in which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 500.","responses":[{"text":"Internal ear","correct":false,"visible":false},{"text":"Pharynx","correct":false,"visible":false},{"text":"Nose","correct":true,"visible":false},{"text":"Face","correct":false,"visible":false},{"text":"Vocal cord","correct":false,"visible":false}]},{"id":1942,"text":"Which of the following bones is not involved in pterion formation?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 836.","responses":[{"text":"Temporal","correct":false,"visible":false},{"text":"Frontal","correct":false,"visible":false},{"text":"Sphenoid","correct":false,"visible":false},{"text":"Parietal","correct":false,"visible":false},{"text":"Occipital","correct":true,"visible":false}]},{"id":1943,"text":"Which of the following does not pass through the superior orbital fissure?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 193.","responses":[{"text":"Ophthalmic vein","correct":false,"visible":false},{"text":"Trochlear nerve","correct":false,"visible":false},{"text":"Oculomotor nerve","correct":false,"visible":false},{"text":"Abducens nerve","correct":false,"visible":false},{"text":"Optic nerve","correct":true,"visible":false}]},{"id":1944,"text":"The lymph from the ear lobule is drained into which of the following lymph nodes?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 975.","responses":[{"text":"Deep cervical nodes","correct":false,"visible":false},{"text":"Superficial cervical nodes","correct":true,"visible":false},{"text":"Superficial inguinal nodes","correct":false,"visible":false},{"text":"Submandibular nodes","correct":false,"visible":false},{"text":"Submental nodes","correct":false,"visible":false}]},{"id":1945,"text":"The lymphatic drainage from the palatine tonsil drains into which of the following lymph nodes?","explanation":"The lymphatic drainage from the palatine tonsil primarily drains into the **jugulodigastric lymph nodes**.\r\n\r\nThe palatine tonsil is a paired lymphoid structure located at the back of the throat, between the palatoglossal and palatopharyngeal arches. It is an important component of the immune system and helps defend against infections. The lymphatic vessels from the palatine tonsil carry lymphatic fluid, which contains immune cells and debris, to nearby lymph nodes for filtration and immune response.\r\n\r\nThe jugulodigastric lymph nodes, also known as the deep cervical lymph nodes, are located along the internal jugular vein in the neck. These nodes receive lymphatic drainage from various structures in the head and neck region, including the palatine tonsil. Therefore, when the palatine tonsil is involved in an infection or inflammation, the lymphatic drainage from the tonsil will pass through the jugulodigastric nodes.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1039.","responses":[{"text":"Submandibular","correct":false,"visible":false},{"text":"Superficial cervical","correct":false,"visible":false},{"text":"Jugulodigastric","correct":true,"visible":false},{"text":"Deep cervical","correct":false,"visible":false},{"text":"Submental","correct":false,"visible":false}]},{"id":1946,"text":"Which of the following statements is not true for the pterygoid venous plexus?","explanation":null,"reference":"Golub B, Bordoni B. Neuroanatomy, pterygoid plexus. In: StatPearls. StatPearls Publishing; 2022. Accessed April 20, 2022. http://www.ncbi.nlm.nih.gov/books/NBK555896/","responses":[{"text":"Receives blood from branches of maxillary artery","correct":false,"visible":false},{"text":"Facial vein communicates with cavernous sinus through inferior ophthalmic vein","correct":true,"visible":false},{"text":"Drains into the maxillary vein","correct":false,"visible":false},{"text":"Connects with cavernous sinus through emissary veins","correct":false,"visible":false},{"text":"Communicates with facial vein by deep facial vein","correct":false,"visible":false}]},{"id":1948,"text":"Which sinus is the most common site for thrombosis?","explanation":null,"reference":"Luo Y, Tian X, Wang X. Diagnosis and treatment of cerebral venous thrombosis: a review. Frontiers in Aging Neuroscience. Published January 30, 2018. Accessed April 21, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5797620/","responses":[{"text":"Cavernous","correct":false,"visible":false},{"text":"Maxillary","correct":false,"visible":false},{"text":"Frontal","correct":false,"visible":false},{"text":"Sphenoidal","correct":false,"visible":false},{"text":"Superior sagittal","correct":true,"visible":false}]},{"id":1950,"text":"Where does the parotid duct open into the oral cavity?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 915.","responses":[{"text":"Maxillary teeth near 2nd molar","correct":true,"visible":false},{"text":"Mandibular teeth near 3rd premolar","correct":false,"visible":false},{"text":"Mandibular teeth near 2nd molar","correct":false,"visible":false},{"text":"Maxillary teeth near 2nd premolar","correct":false,"visible":false},{"text":"Mandibular teeth near 2nd premolar","correct":false,"visible":false}]},{"id":1955,"text":"Which of the following branches of the maxillary artery passes through the foramen spinosum?","explanation":"The branch of the maxillary artery that passes through the **foramen spinosum** is the **middle meningeal artery**.\r\n\r\nThe middle meningeal artery is an important branch of the maxillary artery that supplies the meninges, bones, and other structures in the cranial cavity. It enters the cranial cavity through the foramen spinosum, which is located in the greater wing of the sphenoid bone. Once inside the cranial cavity, the middle meningeal artery runs in the epidural space between the dura mater and the inner surface of the skull.\r\n\r\nThe middle meningeal artery gives off several branches, including the anterior and posterior branches, which supply the meninges and bones of the cranial vault. It also gives rise to a prominent branch called the **middle meningeal artery** that supplies the dura mater and plays a significant role in the blood supply to the brain.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 842.","responses":[{"text":"Nasopalatine artery","correct":false,"visible":false},{"text":"Sphenopalatine artery","correct":false,"visible":false},{"text":"Greater palatine artery","correct":false,"visible":false},{"text":"Middle meningeal artery","correct":true,"visible":false},{"text":"Accessory meningeal artery","correct":false,"visible":false}]},{"id":1978,"text":"A girl wearing tops suffers an infection. Which of the following lymph nodes would be involved?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 975.","responses":[{"text":"Maxillary nodes","correct":false,"visible":false},{"text":"Deep cervical nodes","correct":false,"visible":false},{"text":"Axillary nodes","correct":false,"visible":false},{"text":"Superficial cervical nodes","correct":true,"visible":false},{"text":"Mastoid nodes","correct":false,"visible":false}]},{"id":1979,"text":"Lymph from tongue drain in which of the following lymph nodes?","explanation":"The lymph from the tongue drains into the **jugulo-omohyoid lymph nodes**.\r\n\r\nThe jugulo-omohyoid lymph nodes, also known as the superior deep cervical lymph nodes, are located near the junction of the internal jugular vein and the omohyoid muscle. They receive lymphatic drainage from the tongue, as well as from the floor of the mouth and the sublingual region. \r\n\r\nThese lymph nodes are part of the deep cervical lymph node chain, which plays a crucial role in draining lymph from the head and neck region. The lymphatic vessels from the tongue converge and pass through the jugulo-omohyoid nodes before continuing their drainage into other nodes along the lymphatic pathways.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1028.","responses":[{"text":"Jugulodigastric","correct":false,"visible":false},{"text":"Deep cervical","correct":false,"visible":false},{"text":"Jugulo-omohyoid","correct":true,"visible":false},{"text":"Supraclavicular","correct":false,"visible":false},{"text":"Submental","correct":false,"visible":false}]},{"id":1980,"text":"Which of the following statements is not true for the tongue mucosa?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 298.","responses":[{"text":"The muscle fibers are arranged in all directions","correct":false,"visible":false},{"text":"The surface is not firmly attached to the muscles","correct":true,"visible":false},{"text":"The lower border of tongue is smooth with typical lining mucosa","correct":false,"visible":false},{"text":"Tongue is a striated muscle covered by mucosa","correct":false,"visible":false},{"text":"Elevations of mucous membrane are called lingual papillae","correct":false,"visible":false}]},{"id":1981,"text":"Which one of the following is not a tributary of the external jugular vein?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1004.\r\n\r\n(2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1015.","responses":[{"text":"Anterior jugular vein","correct":false,"visible":false},{"text":"Posterior auricular vein","correct":false,"visible":false},{"text":"Anterior branch of retromandibular vein","correct":true,"visible":false},{"text":"Suprascapular vein","correct":false,"visible":false},{"text":"Posterior branch of retromandibular vein","correct":false,"visible":false}]},{"id":1982,"text":"Which of the following two veins join to form the retromandibular vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1004.","responses":[{"text":"Superficial temporal and maxillary","correct":true,"visible":false},{"text":"Supratrochlear and supraorbital","correct":false,"visible":false},{"text":"Superior and inferior labial","correct":false,"visible":false},{"text":"Angular and inferior labial","correct":false,"visible":false},{"text":"Superior ophthalmic and facial","correct":false,"visible":false}]},{"id":1983,"text":"Which of the following muscles causes the opening of the mouth?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 966.","responses":[{"text":"Sternohyoid","correct":false,"visible":false},{"text":"Omohyoid","correct":false,"visible":false},{"text":"Sternothyroid","correct":false,"visible":false},{"text":"Thyrohyoid","correct":false,"visible":false},{"text":"Digastric","correct":true,"visible":false}]},{"id":1984,"text":"Which of the following is not caused by meperidine?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 572.","responses":[{"text":"Euphoria","correct":false,"visible":false},{"text":"Seizures","correct":false,"visible":false},{"text":"Analgesia","correct":false,"visible":false},{"text":"Miosis","correct":true,"visible":false},{"text":"Mydriasis","correct":false,"visible":false}]},{"id":1989,"text":"At what somite stage does the cranial neuropore close?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 76.","responses":[{"text":"6-10 somite stage","correct":false,"visible":false},{"text":"0-2 somite stage","correct":false,"visible":false},{"text":"14-18 somite stage","correct":false,"visible":false},{"text":"18-20 somite stage","correct":true,"visible":false},{"text":"10-14 somite stage","correct":false,"visible":false}]},{"id":1990,"text":"In which of the following structures does the nasolacrimal duct open into?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 901.","responses":[{"text":"Superior meatus","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Infraorbital foramen","correct":false,"visible":false},{"text":"Inferior meatus","correct":true,"visible":false},{"text":"Middle meatus","correct":false,"visible":false}]},{"id":1991,"text":"Which of the following nerves innervates the palatine tonsils?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1080.","responses":[{"text":"Glossopharyngeal nerve","correct":true,"visible":false},{"text":"Trigeminal nerve","correct":false,"visible":false},{"text":"Optic nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false},{"text":"Hypoglossal nerve","correct":false,"visible":false}]},{"id":1993,"text":"The olfactory epithelium is present in which part of the nasal cavity?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 350.","responses":[{"text":"Lateral","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Medial","correct":false,"visible":false},{"text":"Superior","correct":true,"visible":false},{"text":"Inferior","correct":false,"visible":false}]},{"id":1995,"text":"Which of the following muscles is supplied by two different nerves?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 931.","responses":[{"text":"Stylohyoid","correct":false,"visible":false},{"text":"Sternohyoid","correct":false,"visible":false},{"text":"Sternothyroid","correct":false,"visible":false},{"text":"Digastric","correct":true,"visible":false},{"text":"Mylohyoid","correct":false,"visible":false}]},{"id":1999,"text":"Which of the following nerves supplies the skin over the angle of the mandible?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 857.","responses":[{"text":"Posterior auricular nerve","correct":false,"visible":false},{"text":"Lesser auricular nerve","correct":false,"visible":false},{"text":"Greater auricular nerve","correct":true,"visible":false},{"text":"Mandibular nerve","correct":false,"visible":false},{"text":"Long thoracic nerve","correct":false,"visible":false}]},{"id":2000,"text":"Which of the following is not a branch of the maxillary nerve?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 859, 945.","responses":[{"text":"Supraorbital nerve","correct":true,"visible":false},{"text":"Zygomaticotemporal nerve","correct":false,"visible":false},{"text":"Pharyngeal nerve","correct":false,"visible":false},{"text":"Infraorbital nerve","correct":false,"visible":false},{"text":"Nasopalatine nerve","correct":false,"visible":false}]},{"id":2003,"text":"Which of the following nerves supplies sternocleidomastoid muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1000.","responses":[{"text":"Glossopharyngeal","correct":false,"visible":false},{"text":"Vagus","correct":false,"visible":false},{"text":"Axillary","correct":false,"visible":false},{"text":"Optic nerve","correct":false,"visible":false},{"text":"Accessory","correct":true,"visible":false}]},{"id":2005,"text":"The internal jugular vein is a continuation of which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 844.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Petrosal sinus","correct":false,"visible":false},{"text":"Sigmoid sinus","correct":true,"visible":false},{"text":"Cavernous sinus","correct":false,"visible":false},{"text":"Confluence of sinuses","correct":false,"visible":false}]},{"id":2007,"text":"Which of the following arteries is not a branch of the external carotid artery?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1001, 1008.","responses":[{"text":"Sphenopalatine artery","correct":false,"visible":false},{"text":"Inferior thyroid artery","correct":true,"visible":false},{"text":"Facial","correct":false,"visible":false},{"text":"Superior thyroid artery","correct":false,"visible":false},{"text":"Occipital","correct":false,"visible":false}]},{"id":2008,"text":"Which of the following foramina connects the infratemporal fossa to the middle cranial fossa?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 856.","responses":[{"text":"Foramen ovale","correct":true,"visible":false},{"text":"Foramen magnum","correct":false,"visible":false},{"text":"Foramen lacerum","correct":false,"visible":false},{"text":"Jugular foramen","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":2009,"text":"The loss of heterozygosity (LOH) mutation at 17p causes dysplasia transformation. This involves which gene?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1054.","responses":[{"text":"Rb","correct":false,"visible":false},{"text":"pTEN","correct":false,"visible":false},{"text":"p53","correct":true,"visible":false},{"text":"p16","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":2010,"text":"Which of the following structures passes through incisive fossa?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 942.","responses":[{"text":"Ophthalmic nerve","correct":false,"visible":false},{"text":"Chorda tympani","correct":false,"visible":false},{"text":"Superior alveolar nerve","correct":false,"visible":false},{"text":"Lingual nerve","correct":false,"visible":false},{"text":"Nasopalatine nerve","correct":true,"visible":false}]},{"id":2011,"text":"Which structure does not take part in the formation of an external nose?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1060-1063.","responses":[{"text":"Nasal cartilages","correct":false,"visible":false},{"text":"Inferior conchae","correct":true,"visible":false},{"text":"Maxillary bone","correct":false,"visible":false},{"text":"All of these take part","correct":false,"visible":false},{"text":"Nasal bone","correct":false,"visible":false}]},{"id":2012,"text":"Vitamin A is involved in which of the following process?","explanation":null,"reference":null,"responses":[{"text":"Breakdown of rhodopsin","correct":false,"visible":false},{"text":"Resynthesis of rhodopsin","correct":false,"visible":false},{"text":"Synthesis of rhodopsin","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Storage of iodopsin","correct":false,"visible":false}]},{"id":2013,"text":"Which of the following enzymes is involved in the conversion of retinol to retinal?","explanation":null,"reference":"Kiser PD, Golczak M, Maeda A, Palczewski K. Key enzymes of the retinoid (Visual) cycle in vertebrate retina. Biochimica et biophysica acta. Published January 2012. Accessed April 28, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3158816/","responses":[{"text":"Retinol translocase","correct":false,"visible":false},{"text":"Retinol dehydrogenase in presence of NAD","correct":true,"visible":false},{"text":"Retinol synthase","correct":false,"visible":false},{"text":"Retinol oxidase","correct":false,"visible":false},{"text":"Retinol isomerase","correct":false,"visible":false}]},{"id":2014,"text":"Which of the following is defined by the visual area seen by an eye at a given instant?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 657.","responses":[{"text":"Sight","correct":false,"visible":false},{"text":"Myopia","correct":false,"visible":false},{"text":"Hemianopia","correct":false,"visible":false},{"text":"Field of vision","correct":true,"visible":false},{"text":"Angle of vision","correct":false,"visible":false}]},{"id":2015,"text":"The roof of the posterior triangle of the neck is formed by which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1001.","responses":[{"text":"Superficial fascia","correct":false,"visible":false},{"text":"Investing layer of deep cervical fascia","correct":true,"visible":false},{"text":"Prevertebral layer of deep cervical fascia","correct":false,"visible":false},{"text":"Subcutaneous tissue","correct":false,"visible":false},{"text":"Platysma","correct":false,"visible":false}]},{"id":2016,"text":"Which of the following structures does not pass through the foramen ovale?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 842, 1082.","responses":[{"text":"Accessory meningeal artery","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Middle meningeal artery","correct":true,"visible":false},{"text":"Mandibular division of trigeminal nerve","correct":false,"visible":false},{"text":"Lesser petrosal nerve","correct":false,"visible":false}]},{"id":2088,"text":"Which of these structures does not pass through the jugular foramen?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 842.","responses":[{"text":"Accessory nerve","correct":false,"visible":false},{"text":"Internal jugular vein","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false},{"text":"Labyrinthine artery","correct":true,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false}]},{"id":2089,"text":"What does a lesion in the right optic radiation lead to?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 349.","responses":[{"text":"Complete blindness","correct":false,"visible":false},{"text":"Heteronymous hemianopia","correct":false,"visible":false},{"text":"Right homonymous hemianopia","correct":false,"visible":false},{"text":"Monoccular blindness","correct":false,"visible":false},{"text":"Left homonymous hemianopia","correct":true,"visible":false}]},{"id":2090,"text":"Which of these structures does not pass through the foramen magnum?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 842.","responses":[{"text":"Initial part of the spinal cord","correct":false,"visible":false},{"text":"Hypoglossal nerve","correct":true,"visible":false},{"text":"Vertebral arteries","correct":false,"visible":false},{"text":"Anterior and posterior spinal arteries","correct":false,"visible":false},{"text":"Spinal roots of accessory nerve","correct":false,"visible":false}]},{"id":2091,"text":"Where does the aqueous humor drain into?","explanation":"The **aqueous humor** in the eye drains into the **scleral venous sinus**, also known as the **canal of Schlemm**.\r\n\r\nThe aqueous humor is a clear fluid that is produced by the ciliary body in the posterior chamber of the eye. It nourishes and maintains the shape of the anterior segment of the eye, which includes the cornea and the lens.\r\n\r\nAfter circulating through the anterior chamber, the aqueous humor drains into the scleral venous sinus, which is located at the junction of the cornea and the sclera. The scleral venous sinus acts as a drainage system, allowing the aqueous humor to exit the eye and return to the bloodstream.\r\n\r\nProper drainage of the aqueous humor is important for maintaining the intraocular pressure within a normal range. Disruption of the drainage pathways can lead to increased intraocular pressure, a condition known as glaucoma.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 905.","responses":[{"text":"Sigmoidal sinus","correct":false,"visible":false},{"text":"Sagittal sinus","correct":false,"visible":false},{"text":"Scleral venous sinus","correct":true,"visible":false},{"text":"Ethmoidal sinus","correct":false,"visible":false},{"text":"Cavernous sinus","correct":false,"visible":false}]},{"id":2092,"text":"Which two veins combine to form the facial vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 865.","responses":[{"text":"Angular and superior labial veins","correct":true,"visible":false},{"text":"Retromandibular and maxillary veins","correct":false,"visible":false},{"text":"Retromandibular and supratrochlear veins","correct":false,"visible":false},{"text":"Middle temporal and infratrochlear veins","correct":false,"visible":false},{"text":"Supraorbital and common facial veins","correct":false,"visible":false}]},{"id":2093,"text":"Which of the following is the most common benign tumor of salivary glands?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 744.","responses":[{"text":"Warthin tumor","correct":false,"visible":false},{"text":"Adenoid cystic carcinoma","correct":false,"visible":false},{"text":"Pleomorphic adenoma","correct":true,"visible":false},{"text":"Sialadenitis","correct":false,"visible":false},{"text":"Parotid gland oncocytoma","correct":false,"visible":false}]},{"id":2094,"text":"Which of the following is present in the optic canal?","explanation":"The structure that is present in the optic canal is the **ophthalmic artery**.\r\n\r\nThe optic canal is a bony canal located in the sphenoid bone, through which the optic nerve (cranial nerve II) and ophthalmic artery pass. The ophthalmic artery is the first and main branch of the internal carotid artery within the cranial cavity. It supplies blood to the structures within the orbit, including the retina, choroid, and other ocular structures.\r\n\r\nThe ophthalmic artery accompanies the optic nerve through the optic canal and continues into the orbit as the central retinal artery, which supplies the retina. It gives off various branches within the orbit to supply the extraocular muscles, lacrimal gland, and other structures.\r\n\r\nThe presence of the ophthalmic artery in the optic canal is of clinical significance as vascular disorders or compressive lesions affecting this artery can result in visual disturbances and ocular complications.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 923.","responses":[{"text":"Ophthalmic artery","correct":true,"visible":false},{"text":"Lacrimal artery","correct":false,"visible":false},{"text":"Frontal nerve","correct":false,"visible":false},{"text":"Abducens nerve","correct":false,"visible":false},{"text":"Infraorbital nerve","correct":false,"visible":false}]},{"id":2097,"text":"Posterior 1/3rd of the tongue is supplied by which nerve?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1089.","responses":[{"text":"Glossopharyngeal nerve","correct":true,"visible":false},{"text":"Trigeminal nerve","correct":false,"visible":false},{"text":"Olfactory nerve","correct":false,"visible":false},{"text":"Facial nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false}]},{"id":2098,"text":"Which of the following is incorrect regarding the skull?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 830, 833.","responses":[{"text":"The sphenoid bone is an unpaired bone","correct":false,"visible":false},{"text":"Consists of 22 bones","correct":false,"visible":false},{"text":"The mandible is the inferior most part of the neurocranium","correct":true,"visible":false},{"text":"Viscerocranium is antero-inferior","correct":false,"visible":false},{"text":"Calvaria is dome shaped","correct":false,"visible":false}]},{"id":2102,"text":"Which part does the maxillary artery NOT supply?","explanation":null,"reference":null,"responses":[{"text":"Maxilla","correct":false,"visible":false},{"text":"Nose","correct":false,"visible":false},{"text":"External ear","correct":true,"visible":false},{"text":"Lower jaw","correct":false,"visible":false},{"text":"Cerebral dura mater","correct":false,"visible":false}]},{"id":2104,"text":"The lateral side of the tongue drains into which node?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 951.","responses":[{"text":"Submental nodes","correct":false,"visible":false},{"text":"Superior deep cervical nodes","correct":false,"visible":false},{"text":"Parotid nodes","correct":false,"visible":false},{"text":"Submandibular lymph nodes","correct":true,"visible":false},{"text":"Mastoid nodes","correct":false,"visible":false}]},{"id":2106,"text":"Touch and temperature sensations for the anterior 2/3rd of the tongue are supplied by what nerve?","explanation":null,"reference":null,"responses":[{"text":"Hypoglossal nerve","correct":false,"visible":false},{"text":"Mandibular branch of trigeminal nerve","correct":true,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false},{"text":"Facial nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false}]},{"id":2107,"text":"Where are olfactory cells present?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 350.","responses":[{"text":"Conchae","correct":false,"visible":false},{"text":"Respiratory epithelium","correct":false,"visible":false},{"text":"Vestibule","correct":false,"visible":false},{"text":"Olfactory epithelium","correct":true,"visible":false},{"text":"Uncus","correct":false,"visible":false}]},{"id":2108,"text":"The corneal epithelium consists of which cell type?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 84, 491.","responses":[{"text":"Simple columnar cells","correct":false,"visible":false},{"text":"Stratified squamous non-keratinized cells","correct":true,"visible":false},{"text":"Transitional cells","correct":false,"visible":false},{"text":"Stratified squamous keratinized cells","correct":false,"visible":false},{"text":"Stratified columnar cells","correct":false,"visible":false}]},{"id":2112,"text":"Middle conchae is part of which bone?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 966.","responses":[{"text":"Temporal","correct":false,"visible":false},{"text":"Sphenoid","correct":false,"visible":false},{"text":"Ethmoid","correct":true,"visible":false},{"text":"Frontal","correct":false,"visible":false},{"text":"Nasal","correct":false,"visible":false}]},{"id":2114,"text":"The gland that secretes calcitonin is formed from which pharyngeal pouch?","explanation":"The gland that secretes calcitonin, known as the **thyroid gland**, is formed from the **4th pharyngeal pouch** during embryonic development.\r\n\r\nDuring early development, the pharyngeal arches and pouches play a crucial role in the formation of various structures in the head and neck region. The thyroid gland originates from the endodermal cells of the **floor of the 4th pharyngeal pouch**. These cells migrate downward and fuse in the midline to form the primordial thyroid gland.\r\n\r\nThe thyroid gland is responsible for the production and secretion of various hormones, including calcitonin. Calcitonin plays a role in regulating calcium and phosphate metabolism in the body.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 163-164.","responses":[{"text":"2nd","correct":false,"visible":false},{"text":"3rd","correct":false,"visible":false},{"text":"4th","correct":true,"visible":false},{"text":"5th","correct":false,"visible":false},{"text":"1st","correct":false,"visible":false}]},{"id":2150,"text":"Which structure is not attached to styloid process?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 850, 928, 1011, 1046.","responses":[{"text":"Stylohyoid muscle","correct":false,"visible":false},{"text":"Stylopharyngeus muscle","correct":false,"visible":false},{"text":"Stylomandibular ligament","correct":false,"visible":false},{"text":"Styloglossus muscle","correct":false,"visible":false},{"text":"Sphenomandibular ligament","correct":true,"visible":false}]},{"id":2151,"text":"What is the point of intersection of the lambdoid and sagittal sutures?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 836.","responses":[{"text":"Pterion","correct":false,"visible":false},{"text":"Nasion","correct":false,"visible":false},{"text":"Lambda","correct":true,"visible":false},{"text":"Asterion","correct":false,"visible":false},{"text":"Bregma","correct":false,"visible":false}]},{"id":2152,"text":"What is the H-shaped suture on the lateral side of the skull called?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 837.","responses":[{"text":"Pterion","correct":true,"visible":false},{"text":"Inion","correct":false,"visible":false},{"text":"Bregma","correct":false,"visible":false},{"text":"Lambda","correct":false,"visible":false},{"text":"Asterion","correct":false,"visible":false}]},{"id":2153,"text":"The maxillary sinus drains into which structure?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 963.","responses":[{"text":"Superior nasal meatus","correct":false,"visible":false},{"text":"Middle nasal meatus","correct":true,"visible":false},{"text":"Inferior nasal meatus","correct":false,"visible":false},{"text":"Superior conchae","correct":false,"visible":false},{"text":"Inferior conchae","correct":false,"visible":false}]},{"id":2154,"text":"What of the following structures does not pass through the carotid sheath?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 997.","responses":[{"text":"Vagus nerve","correct":false,"visible":false},{"text":"Internal carotid artery","correct":false,"visible":false},{"text":"Common carotid artery","correct":false,"visible":false},{"text":"External carotid artery","correct":true,"visible":false},{"text":"Internal jugular vein","correct":false,"visible":false}]},{"id":2155,"text":"Which fascia of the neck divides into two to cover the sternocleidomastoid and trapezius muscles?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 996.","responses":[{"text":"Prevertebral layer","correct":false,"visible":false},{"text":"Investing layer","correct":true,"visible":false},{"text":"Superficial cervical fascia","correct":false,"visible":false},{"text":"Carotid sheath","correct":false,"visible":false},{"text":"Pretracheal layer","correct":false,"visible":false}]},{"id":2156,"text":"Low pitch sound is detected by which structure?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 985.","responses":[{"text":"Semicircular canals","correct":false,"visible":false},{"text":"Auricle","correct":false,"visible":false},{"text":"Helicotrema","correct":true,"visible":false},{"text":"Cochlea","correct":false,"visible":false},{"text":"Utricle","correct":false,"visible":false}]},{"id":2157,"text":"Astigmatism is caused due to curvature loss of which structure?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 633.","responses":[{"text":"Retina","correct":false,"visible":false},{"text":"Eye brows","correct":false,"visible":false},{"text":"Iris","correct":false,"visible":false},{"text":"Lens","correct":true,"visible":false},{"text":"Pupil","correct":false,"visible":false}]},{"id":2158,"text":"A person has pain near the angle of the mandible and is not able to close his mouth due to spasm of a muscle. What is this muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 928.","responses":[{"text":"Platysma","correct":false,"visible":false},{"text":"Lateral pterygoid","correct":false,"visible":false},{"text":"Medial pterygoid","correct":true,"visible":false},{"text":"Digastric","correct":false,"visible":false},{"text":"Geniohyoid","correct":false,"visible":false}]},{"id":2159,"text":"What is the point of junction of the coronal and sagittal sutures?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 836.","responses":[{"text":"Pterion","correct":false,"visible":false},{"text":"Asterion","correct":false,"visible":false},{"text":"Inion","correct":false,"visible":false},{"text":"Lambda","correct":false,"visible":false},{"text":"Bregma","correct":true,"visible":false}]},{"id":2160,"text":"A person has right eye blindness. When light is shown on his left eye, what will be the pupillary response?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 328-329.","responses":[{"text":"Only the left pupil will constrict","correct":false,"visible":false},{"text":"No response","correct":false,"visible":false},{"text":"Both pupils will constrict","correct":true,"visible":false},{"text":"Both pupils will dilate","correct":false,"visible":false},{"text":"Closure of eye lids","correct":false,"visible":false}]},{"id":2161,"text":"A person has right eye blindness. When a light is shined on his right eye, what will be the pupillary response?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 249, 328-329.","responses":[{"text":"Both pupils will constrict","correct":false,"visible":false},{"text":"Only the left pupil will constrict","correct":false,"visible":false},{"text":"No response","correct":true,"visible":false},{"text":"Closure of eye lids","correct":false,"visible":false},{"text":"Both pupils will dilate","correct":false,"visible":false}]},{"id":2162,"text":"What nerves are affected in jugular foramen syndrome?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 842.","responses":[{"text":"CN 10, 11 and 12","correct":false,"visible":false},{"text":"CN 9, 10 and 11","correct":true,"visible":false},{"text":"CN 8, 9 and 10","correct":false,"visible":false},{"text":"CN 7, 8 and 10","correct":false,"visible":false},{"text":"CN 7, 8 and 9","correct":false,"visible":false}]},{"id":2163,"text":"Which of the following is not part of the temporal bone?","explanation":null,"reference":null,"responses":[{"text":"Tympanic part","correct":false,"visible":false},{"text":"Petromastoid part","correct":false,"visible":false},{"text":"Nasal part","correct":true,"visible":false},{"text":"Zygomatic part","correct":false,"visible":false},{"text":"Squamous part","correct":false,"visible":false}]},{"id":2226,"text":"Anything that might be taken into the nose accidentally goes into the pharynx through what structure?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 964, 1041.","responses":[{"text":"Nasopharynx","correct":true,"visible":false},{"text":"Eustachian tube","correct":false,"visible":false},{"text":"Nasal vestibules","correct":false,"visible":false},{"text":"Meatus","correct":false,"visible":false},{"text":"Conchae","correct":false,"visible":false}]},{"id":19986,"text":"Which of the following is the best initial imaging modality for diagnosing a thyroglossal duct cyst?","explanation":null,"reference":"Amos J, Shermetaro C. Thyroglossal duct cyst. In: StatPearls. StatPearls Publishing; 2023. Accessed September 30, 2023. http://www.ncbi.nlm.nih.gov/books/NBK519057/","responses":[{"text":"CT scan","correct":false,"visible":false},{"text":"MRI scan","correct":false,"visible":false},{"text":"Ultrasound","correct":true,"visible":false},{"text":"PET scan","correct":false,"visible":false},{"text":"X-ray","correct":false,"visible":false}]}
]

